const item = $input.first().json;
const body = item.body || item;
const data = body.data || {};
const key = data.key || {};

let remoteJid = key.remoteJid || body.remoteJid || '';
if ((remoteJid.includes('@lid') || !remoteJid) && body.sender) {
  remoteJid = body.sender;
}

if (body.event && body.event !== 'messages.upsert') {
  return [null];
}

const msg = data.message || {};
const mensagem = msg.conversation
  || msg.extendedTextMessage?.text
  || msg.imageMessage?.caption
  || msg.documentMessage?.caption
  || msg.videoMessage?.caption
  || '';

const numero = remoteJid.replace('@s.whatsapp.net', '');
const pushName = data.pushName || body.pushName || '';
const fromMe = key.fromMe === true;

if (fromMe || !mensagem) {
  return [null];
}

return [{
  json: { remoteJid, numero, mensagem, pushName }
}];

const entrada = $input.first().json;

const { remoteJid, numero, mensagem, pushName } = entrada;
const estadoAtual = entrada.estado || 'SAUDACAO';
const dados = entrada.dados || {};

const msgLower = mensagem.toLowerCase().trim();
const sim = ['sim', 's', 'ss', 'claro', 'ok', 'pode ser', 'vamos', 'bora', 'yes'];
const nao = ['não', 'nao', 'n', 'ñ', 'nem', 'no'];

let resposta = '';
let proximoEstado = estadoAtual;
let leadPronto = false;

switch (estadoAtual) {

  case 'SAUDACAO':
    resposta = `Olá${pushName ? ', ' + pushName : ''}! 👋

Bem-vindo(a) à *PRO MODA Têxtil*!

Somos uma indústria têxtil brasileira com mais de 15 anos de experiência, especializada em tecidos para:
• Hospitalar 🏥
• WorkWear (uniformes) 👔
• Decoração 🏠
• Colchões 🛏️
• Forro de Bolso 👖

📌 *Atendemos exclusivamente pessoas jurídicas (empresas).*

Você é pessoa jurídica? (Sim/Não)`;
    proximoEstado = 'VALIDANDO_PJ';
    break;

  case 'VALIDANDO_PJ':
    ehSim = sim.some(p => msgLower.startsWith(p) || msgLower.includes(' ' + p) || msgLower === p);
    ehNao = nao.some(p => msgLower.startsWith(p) || msgLower === p);

    if (ehNao || msgLower.includes('física') || msgLower.includes('fisica')) {
      resposta = 'Infelizmente atendemos apenas pessoas jurídicas (empresas com CNPJ ativo). 😕

Se no futuro você abrir um CNPJ, estaremos aqui para ajudar!

Agradecemos o contato! 🙏';
      proximoEstado = 'ENCERRADO';
      leadPronto = false;
    } else if (ehSim || msgLower.includes('jurídica') || msgLower.includes('juridica') || msgLower.includes('empresa') || msgLower.includes('cnpj') || msgLower.includes('sou')) {
      resposta = 'Ótimo! 😊

Para continuar, preciso de algumas informações:

1️⃣ *Razão Social* da empresa
2️⃣ *CNPJ*
3️⃣ *Nome para contato*

Fique à vontade para enviar os dados em uma única mensagem ou separadamente.';
      proximoEstado = 'COLETANDO_DADOS';
    } else {
      resposta = 'Desculpe, não entendi. 🧐

Você é *pessoa jurídica* (empresa)? Responda Sim ou Não.';
      proximoEstado = 'VALIDANDO_PJ';
    }
    break;

  case 'COLETANDO_DADOS':
    const cnpjMatch = mensagem.match(/\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}/);
    if (cnpjMatch) {
      dados.cnpj = cnpjMatch[0];
    }

    if (mensagem.length > 5 && !dados.razaoSocial) {
      const linhas = mensagem.split('\n').filter(l => l.trim());
      for (const linha of linhas) {
        const l = linha.trim();
        const cnpj = l.match(/\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}/);
        if (cnpj && !dados.cnpj) {
          dados.cnpj = cnpj[0];
        } else if (l.replace(/\D/g, '').length >= 8 && l.replace(/\D/g, '').length <= 14) {
          if (l.includes('-') || l.includes('/') || l.includes('.')) {
            dados.cnpj = l;
          } else {
            dados.celular = l.replace(/\D/g, '');
          }
        } else if (!dados.razaoSocial && l.length > 5) {
          dados.razaoSocial = l;
        }
      }
    }

    if (!dados.nomeContato && pushName) {
      dados.nomeContato = pushName;
    }

    if (dados.cnpj && dados.razaoSocial) {
      if (!dados.nomeContato) dados.nomeContato = pushName || 'Não informado';
      resposta = `Perfeito! ✅ Dados registrados:

📋 *Empresa:* ${dados.razaoSocial}
🔢 *CNPJ:* ${dados.cnpj}
👤 *Contato:* ${dados.nomeContato}

---

Você já conhece os produtos da *PRO MODA Têxtil*? (Sim/Não)`;
      proximoEstado = 'PERGUNTANDO_PRODUTOS';
    } else {
      let pedindo = 'Ainda preciso de algumas informações:\n\n';
      if (!dados.razaoSocial) pedindo += '📌 *Razão Social* da empresa\n';
      if (!dados.cnpj) pedindo += '📌 *CNPJ* da empresa\n';
      if (!dados.nomeContato) pedindo += '📌 *Nome para contato*\n';
      pedindo += '\nPode enviar os dados que faltam? 🙏';
      resposta = pedindo;
      proximoEstado = 'COLETANDO_DADOS';
    }
    break;

  case 'PERGUNTANDO_PRODUTOS':
    ehSim = sim.some(p => msgLower.startsWith(p) || msgLower.includes(' ' + p) || msgLower === p);
    ehNao = nao.some(p => msgLower.startsWith(p) || msgLower === p);

    if (ehSim || ehNao || msgLower.includes('produto') || msgLower.includes('qual') || msgLower.includes('conheço') || msgLower.includes('conheco')) {
      resposta = `Ótimo! Conheça nossas linhas de produtos: 🎯

━━━━━━━━━━━━━━━━
🏥 *LINHA HOSPITALAR*
Tecidos para lençóis hospitalares com resistência, conforto e alta durabilidade.

━━━━━━━━━━━━━━━━
👔 *WORKWEAR*
Uniformes profissionais com durabilidade, desempenho e padronização de cores.

━━━━━━━━━━━━━━━━
🏠 *DECORAÇÃO*
Tecidos para lençol e enxoval, com toque macio e visual sofisticado.

━━━━━━━━━━━━━━━━
🛏️ *COLCHÕES*
Tecidos de alta performance para o setor colchoeiro.

━━━━━━━━━━━━━━━━
👖 *FORRO DE BOLSO*
Tecidos resistentes ao atrito diário para bolso de calça.
━━━━━━━━━━━━━━━━

Qual linha te despertou mais interesse? 😊`;
      proximoEstado = 'MOSTRANDO_PRODUTOS';
    } else {
      resposta = `Não entendi 😅

Você já conhece nossos produtos? (Sim/Não)

Posso te mostrar o que fazemos!`;
      proximoEstado = 'PERGUNTANDO_PRODUTOS';
    }
    break;

  case 'MOSTRANDO_PRODUTOS':
    resposta = `Que bom! Fico feliz com seu interesse! 😊

📞 Um dos nossos *representantes comerciais* entrará em contato com você em *até 5 minutos* pelo WhatsApp para conversarmos sobre suas necessidades.

Enquanto isso, você pode conhecer mais sobre a Pro MODA:
🌐 www.promodatextil.com.br
📧 contato@promodatextil.com.br
📱 (19) 99832-2339

Agradecemos o contato! 🙏🚀`;
    proximoEstado = 'AGUARDANDO_REPRESENTANTE';
    leadPronto = true;
    break;

  case 'AGUARDANDO_REPRESENTANTE':
    resposta = '✅ Já registramos seu interesse! Um representante entrará em contato em breve. 😊';
    proximoEstado = 'AGUARDANDO_REPRESENTANTE';
    break;

  case 'ENCERRADO':
    resposta = '✅ Conversa encerrada. Se precisar de algo no futuro, é só chamar! 😊';
    proximoEstado = 'ENCERRADO';
    break;

  default:
    resposta = 'Olá! Como posso ajudar? 😊';
    proximoEstado = 'SAUDACAO';
}

return [{
  json: {
    remoteJid,
    numero,
    mensagem: resposta,
    proximoEstado,
    dados,
    leadPronto
  }
}];
